if (items.length === 0 || !items[0].json.results) return [];

// Format and clean up the nested results from GAQL stream
return items[0].json.results.map(row => {
  let flattened = {};
  for (const [key, value] of Object.entries(row)) {
    if (typeof value === 'object' && value !== null) {
      for (const [subKey, subValue] of Object.entries(value)) {
        flattened[`${key}_${subKey}`] = subValue;
      }
    } else {
      flattened[key] = value;
    }
  }
  return { json: flattened };
});

